/**
 * @fileType test
 * @domain infra | pipeline-health
 * @pattern tdd-red-phase
 * @ai-summary Unit tests for PipelineHealthReport class and getStageTimeout helper
 */
import { describe, it, expect } from 'vitest'
import { PipelineHealthReport } from '@/infra/utils/pipeline-health'
import { getStageTimeout } from '@/infra/utils/pipeline-health'

describe('PipelineHealthReport', () => {
  describe('instantiation', () => {
    it('should export PipelineHealthReport class', () => {
      const reporter = new PipelineHealthReport()
      expect(reporter).toBeDefined()
    })
  })

  describe('checkStageHealth', () => {
    it('should return health status for valid stage name', () => {
      const reporter = new PipelineHealthReport()
      const status = reporter.checkStageHealth('architect')
      expect(status).toBeDefined()
      expect(status.stage).toBe('architect')
      expect(typeof status.healthy).toBe('boolean')
      expect(typeof status.message).toBe('string')
      expect(status.timestamp).toBeDefined()
    })

    it('should return healthy status for known stages', () => {
      const reporter = new PipelineHealthReport()
      const status = reporter.checkStageHealth('taskify')
      expect(status.healthy).toBe(true)
      expect(status.stage).toBe('taskify')
    })

    it('should return healthy status for build stage', () => {
      const reporter = new PipelineHealthReport()
      const status = reporter.checkStageHealth('build')
      expect(status.healthy).toBe(true)
      expect(status.stage).toBe('build')
    })

    it('should return healthy status for review stage', () => {
      const reporter = new PipelineHealthReport()
      const status = reporter.checkStageHealth('review')
      expect(status.healthy).toBe(true)
      expect(status.stage).toBe('review')
    })

    it('should throw on empty stage name', () => {
      const reporter = new PipelineHealthReport()
      expect(() => reporter.checkStageHealth('')).toThrow()
    })

    it('should throw on whitespace-only stage name', () => {
      const reporter = new PipelineHealthReport()
      expect(() => reporter.checkStageHealth('   ')).toThrow()
    })

    it('should throw on null-like input', () => {
      const reporter = new PipelineHealthReport()
      expect(() => reporter.checkStageHealth(null as unknown as string)).toThrow()
    })
  })

  describe('generateReport', () => {
    it('should return a report object', () => {
      const reporter = new PipelineHealthReport()
      const report = reporter.generateReport()
      expect(report).toBeDefined()
    })

    it('should include overallHealth field', () => {
      const reporter = new PipelineHealthReport()
      const report = reporter.generateReport()
      expect(report).toHaveProperty('overallHealth')
      expect(typeof report.overallHealth).toBe('string')
    })

    it('should include stages array', () => {
      const reporter = new PipelineHealthReport()
      const report = reporter.generateReport()
      expect(report).toHaveProperty('stages')
      expect(Array.isArray(report.stages)).toBe(true)
    })

    it('should include generatedAt timestamp', () => {
      const reporter = new PipelineHealthReport()
      const report = reporter.generateReport()
      expect(report).toHaveProperty('generatedAt')
      expect(report.generatedAt).toBeDefined()
    })

    it('should include recommendations array', () => {
      const reporter = new PipelineHealthReport()
      const report = reporter.generateReport()
      expect(report).toHaveProperty('recommendations')
      expect(Array.isArray(report.recommendations)).toBe(true)
    })
  })

  describe('getRetryRecommendation', () => {
    it('should return retry strategy for valid stage', () => {
      const reporter = new PipelineHealthReport()
      const recommendation = reporter.getRetryRecommendation('build')
      expect(recommendation).toBeDefined()
      expect(recommendation.stage).toBe('build')
      expect(recommendation).toHaveProperty('strategy')
      expect(recommendation).toHaveProperty('maxRetries')
      expect(recommendation).toHaveProperty('timeout')
    })

    it('should return retry strategy for architect stage', () => {
      const reporter = new PipelineHealthReport()
      const recommendation = reporter.getRetryRecommendation('architect')
      expect(recommendation.stage).toBe('architect')
      expect(typeof recommendation.strategy).toBe('string')
      expect(typeof recommendation.maxRetries).toBe('number')
      expect(typeof recommendation.timeout).toBe('number')
    })

    it('should throw on empty stage name', () => {
      const reporter = new PipelineHealthReport()
      expect(() => reporter.getRetryRecommendation('')).toThrow()
    })

    it('should throw on whitespace-only stage name', () => {
      const reporter = new PipelineHealthReport()
      expect(() => reporter.getRetryRecommendation('   ')).toThrow()
    })

    it('should throw on null-like input', () => {
      const reporter = new PipelineHealthReport()
      expect(() => reporter.getRetryRecommendation(null as unknown as string)).toThrow()
    })
  })
})

describe('getStageTimeout', () => {
  it('should export getStageTimeout function', () => {
    expect(typeof getStageTimeout).toBe('function')
  })

  it('should return number for taskify stage', () => {
    const timeout = getStageTimeout('taskify')
    expect(typeof timeout).toBe('number')
    expect(timeout).toBeGreaterThan(0)
  })

  it('should return number for architect stage', () => {
    const timeout = getStageTimeout('architect')
    expect(typeof timeout).toBe('number')
    expect(timeout).toBeGreaterThan(0)
  })

  it('should return number for build stage', () => {
    const timeout = getStageTimeout('build')
    expect(typeof timeout).toBe('number')
    expect(timeout).toBeGreaterThan(0)
  })

  it('should return number for review stage', () => {
    const timeout = getStageTimeout('review')
    expect(typeof timeout).toBe('number')
    expect(timeout).toBeGreaterThan(0)
  })

  it('should return number for gap stage', () => {
    const timeout = getStageTimeout('gap')
    expect(typeof timeout).toBe('number')
    expect(timeout).toBeGreaterThan(0)
  })

  it('should return number for plan-gap stage', () => {
    const timeout = getStageTimeout('plan-gap')
    expect(typeof timeout).toBe('number')
    expect(timeout).toBeGreaterThan(0)
  })

  it('should return default timeout for unknown stage', () => {
    const timeout = getStageTimeout('unknown-stage')
    expect(typeof timeout).toBe('number')
    expect(timeout).toBeGreaterThan(0)
  })

  it('should return default timeout for random string', () => {
    const timeout = getStageTimeout('random')
    expect(typeof timeout).toBe('number')
    expect(timeout).toBeGreaterThan(0)
  })
})
TEST_EOF

